import{_ as t,C as d,o as r,c as a,a7 as c,E as l}from"./chunks/framework.D3qk93i9.js";const T=JSON.parse('{"title":"固件烧录","description":"使用浏览器完成 OSRBOT 设备的普通 app 升级或 BOOT 恢复出厂烧录。","frontmatter":{"title":"固件烧录","description":"使用浏览器完成 OSRBOT 设备的普通 app 升级或 BOOT 恢复出厂烧录。"},"headers":[],"relativePath":"updater.md","filePath":"updater.md","lastUpdated":1781680980000}'),i={name:"updater.md"};function p(s,e,n,_,m,u){const o=d("FirmwareUpdater");return r(),a("div",null,[e[0]||(e[0]=c('<h1 id="固件烧录" tabindex="-1">固件烧录 <a class="header-anchor" href="#固件烧录" aria-label="Permalink to &quot;固件烧录&quot;">​</a></h1><blockquote><p>需要 Chrome 或 Edge 浏览器（支持 Web Serial API）。</p></blockquote><p>这个页面提供两种烧录方式：</p><ul><li><strong>普通升级</strong>：设备正常开机，不需要进入 BOOT，只更新 app 固件。远端固件可以直接从当前仓库例程中选择；自定义 URL 必须填写完整 HTTPS 地址。</li><li><strong>恢复出厂</strong>：第一次刷机、恢复出厂或固件无法启动时使用，需要进入 BOOT 下载模式并写入站内 full flash 固件。</li></ul><p>本地 <code>.bin</code> 文件仍可用于内部测试或临时固件验证。</p><p>例程固件刷入后，建议测试流程：</p><ol><li>打开串口监视器，发送 <code>diag</code>，确认芯片 SN、Flash、Heap、I2C、IMU、地磁、SBUS 状态。</li><li>发送 <code>imu</code> 和 <code>mag</code>，轻微转动开发板，确认原始数据会变化。</li><li>发送 <code>ledtest</code> 和 <code>beeptest</code>，确认 LED 与蜂鸣器工作。</li><li>发送 <code>rc</code>，推动遥控器摇杆，确认通道数值变化。</li><li>架空车辆后发送 <code>servo left</code>、<code>servo center</code>、<code>servo right</code>，确认舵机方向。</li><li>架空车辆后发送 <code>motor fwd</code>、<code>motor rev</code>、<code>motor stop</code>，确认电机正反转。</li><li>架空车辆后发送 <code>drive on</code>，用遥控器 CH0/CH2 做受限低速测试；结束发送 <code>drive off</code>。</li></ol>',7)),l(o)])}const O=t(i,[["render",p]]);export{T as __pageData,O as default};
